import './Companies.css';

const Companies = () => {
  return (
    <section className="companies">
      <p>Worked with</p>
      <div className="company-logos">
        <span>ClickUp</span>
        <span>Dropbox</span>
        <span>PAYCHEX</span>
        <span>elastic</span>
        <span>stripe</span>
      </div>
    </section>
  );
}

export default Companies;
